const now = new Date();
const today = now.toISOString().slice(0, 10);
const lookback = new Date(now - 60 * 24 * 60 * 60 * 1000);
const startDate = lookback.toISOString().slice(0, 10);
const lastMonth = new Date(now.getFullYear(), now.getMonth() - 1, 1)
  .toLocaleDateString('en-US', { month: 'long', year: 'numeric' });

// ── ACCOUNT IDs ───────────────────────────────────────────────────────────────
// List your on-budget account IDs here (checking + credit cards).
// Run Workflow 00 (Discovery) to get these IDs.
// The Rule Digest looks at transactions across all of these accounts.
const accountIds = [
  'GET_FROM_WF00',  // e.g. Checking
  'GET_FROM_WF00',  // e.g. Credit Card 1
  'GET_FROM_WF00',  // e.g. Credit Card 2
  // Add more as needed — one ID per line
];

return [{ json: {
  bridgeUrl:        'http://actual-bridge:3788',
  notionDatabaseId: 'REPLACE_WITH_YOUR_NOTION_RULES_DB_ID',
  telegramChatId:   'REPLACE_WITH_YOUR_TELEGRAM_CHAT_ID',
  accountIds, startDate, today, lastMonth
} }];

const items = $input.all();
const config = $('Config').item.json;
const allTx = [];
for (const item of items) {
  const txs = item.json.data || [];
  for (const tx of txs) {
    if (tx.amount < 0 && !tx.starting_balance_flag && !tx.transfer_id) {
      allTx.push({
        date: tx.date,
        payee: tx.imported_payee || tx.payee_name || 'Unknown',
        amount: Math.abs(tx.amount) / 100
      });
    }
  }
}
return [{ json: { ...config, allTransactions: allTx } }];

const notionRes = $input.item.json;
const config = $('Merge Transactions').item.json;

// Build known payees map from Notion
const knownPayees = {};
for (const page of (notionRes.results || [])) {
  const props = page.properties || {};
  const name = props.Payee && props.Payee.title && props.Payee.title[0]
    ? props.Payee.title[0].plain_text : null;
  const status = props.Status && props.Status.select ? props.Status.select.name : null;
  if (name) knownPayees[name.toLowerCase()] = { status };
}

// Group transactions by payee
const groups = {};
for (const tx of (config.allTransactions || [])) {
  const key = tx.payee.toLowerCase();
  if (!groups[key]) groups[key] = { name: tx.payee, txs: [] };
  groups[key].txs.push(tx);
}

// Detect patterns - skip already accepted or declined
const patterns = [];
for (const [key, g] of Object.entries(groups)) {
  if (g.txs.length < 2) continue;
  const known = knownPayees[key];
  if (known && (known.status === 'Accepted' || known.status === 'Declined')) continue;

  const amounts = g.txs.map(t => t.amount);
  const avg = amounts.reduce((a, b) => a + b, 0) / amounts.length;
  const variance = ((Math.max(...amounts) - Math.min(...amounts)) / avg) * 100;

  const dates = g.txs.map(t => new Date(t.date)).sort((a, b) => a - b);
  const intervals = [];
  for (let i = 1; i < dates.length; i++) {
    intervals.push(Math.round((dates[i] - dates[i-1]) / 86400000));
  }
  const avgInterval = intervals.length > 0
    ? intervals.reduce((a, b) => a + b, 0) / intervals.length : 0;

  let type = 'irregular';
  if (avgInterval >= 6 && avgInterval <= 8) type = 'weekly';
  else if (avgInterval >= 13 && avgInterval <= 16) type = 'bi-weekly';
  else if (avgInterval >= 27 && avgInterval <= 35) type = 'monthly';
  else if (g.txs.length >= 3) type = 'frequent';
  if (type === 'irregular' && g.txs.length < 3) continue;

  const desc = g.txs.length + 'x / 60 days, ' + type +
    (variance < 5 ? ', fixed $' + avg.toFixed(2) : ', avg $' + avg.toFixed(2) + ' (' + Math.round(variance) + '% variance)');

  patterns.push({ payee: g.name, patternDesc: desc, count: g.txs.length });
}

if (patterns.length === 0) return [{ json: { ...config, noPatterns: true } }];

const patternList = patterns.map(p => p.payee + ' | ' + p.patternDesc).join('\n');

const prompt = 'You are a budget assistant.\n\n' +
  'Recurring payment patterns detected in last 60 days:\n' + patternList + '\n\n' +
  'Available categories:\nMortgage payment, Parent loan payment, Car loan payment, Unsecured personal loan payment, ' +
  'Internet or Xfinity bill, Gas utility DTE or Consumers Energy, Electric utility bill, Water bill, ' +
  'Cell phone or mobile phone bill, Streaming services Netflix Hulu Disney Plus, ' +
  'Home improvement or maintenance repair, Gas station or fuel, Auto insurance premium, ' +
  'Car repair or maintenance, Groceries Kroger Meijer Costco Aldi, ' +
  'Restaurants fast food coffee shops DoorDash Grubhub, Hantz Financial Services advisor fee, ' +
  'House cleaning service, OnStar subscription, Other subscription or professional service, ' +
  'School fees lunch account supplies MISTAR, Hockey fees gear ice rink, ' +
  'Other kids activities allowance sports misc, Doctor pharmacy medical gym fitness, ' +
  'Haircut salon barber personal grooming, Clothing shoes apparel, ' +
  'Entertainment hobbies events concerts tickets, Gifts for others birthday holiday, ' +
  'Pet food vet grooming pet supplies, Amazon purchase online order, ' +
  'Other online or retail shopping store, Miscellaneous hard to categorize one-off\n\n' +
  'For each pattern suggest a category. Skip patterns too ambiguous to categorize reliably.\n' +
  'Respond ONLY with a raw JSON array, no markdown, no code fences:\n' +
  '[{"payee": "exact name", "category": "exact category name", "confidence": "High|Medium|Low", "reason": "one sentence"}, ...]';

return [{ json: { ...config, patterns, prompt } }];

const claudeRes = $input.item.json;
const config = $('Detect Patterns').item.json;
let suggestions = [];
try {
  const raw = claudeRes.content && claudeRes.content[0] ? claudeRes.content[0].text : '[]';
  const cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  suggestions = JSON.parse(cleaned);
} catch (e) {
  suggestions = [];
}
// Enrich with pattern data
const enriched = suggestions.map(s => {
  const p = (config.patterns || []).find(x => x.payee.toLowerCase() === s.payee.toLowerCase());
  return { ...s, patternDesc: p ? p.patternDesc : '' };
});
if (enriched.length === 0) return [{ json: { ...config, noPatterns: true } }];
return enriched.map(s => ({
  json: {
    notionDatabaseId: config.notionDatabaseId,
    telegramChatId: config.telegramChatId,
    lastMonth: config.lastMonth,
    allSuggestions: enriched,
    suggestion: s
  }
}));

const items = $input.all();
const config = items[0].json;
const suggestions = config.allSuggestions || [];
let msg = 'MONTHLY RULE DIGEST - ' + config.lastMonth + '\n\n';
if (suggestions.length === 0) {
  msg += 'No new recurring patterns found this month.';
} else {
  msg += suggestions.length + ' new pattern(s) added to Notion for review:\n\n';
  const high = suggestions.filter(s => s.confidence === 'High');
  const med = suggestions.filter(s => s.confidence === 'Medium');
  const low = suggestions.filter(s => s.confidence === 'Low');
  if (high.length > 0) {
    msg += 'HIGH (create rule in Actual):\n';
    high.forEach(s => { msg += '  - ' + s.payee + ' -> ' + s.category + '\n    ' + s.patternDesc + '\n'; });
    msg += '\n';
  }
  if (med.length > 0) {
    msg += 'MEDIUM (review first):\n';
    med.forEach(s => { msg += '  - ' + s.payee + ' -> ' + s.category + '\n    ' + s.patternDesc + '\n'; });
    msg += '\n';
  }
  if (low.length > 0) {
    msg += 'LOW (probably skip):\n';
    low.forEach(s => { msg += '  - ' + s.payee + '\n'; });
    msg += '\n';
  }
  msg += 'Review in Notion: https://notion.so/3a47cc37a3684de1a7c74718b6c65253\n';
  msg += 'Create rules in Actual: http://your-actual-budget-url';
}
